  "group": "क्वेरी क्षमताएँ",
  "options": [
    {
      "text": "ElastiCache",
      "hint": "मुख्यतः एक इन‑मेमोरी कैश; नए Valkey संस्करणों में खोज सुविधाएँ शामिल हैं।"
    },
    {
      "text": "OpenSearch"
    },
    {
      "text": "Neptune",
      "hint": "उन्नत क्वेरी क्षमताओं वाला ग्राफ डेटाबेस"
    },
    {
      "text": "Redshift",
      "hint": "जटिल विश्लेषणात्मक क्वेरीज़"
    },
    {
      "text": "DocumentDB",
      "hint": "MongoDB‑संगत क्वेरीज़"
    }
  ],
  "questionProse": [
    "इनमें से कौन सी AWS सेवा पूर्ण‑पाठ खोज और खोज विश्लेषण के लिए विशेष रूप से निर्मित है?"
  ],
  "explanationProse": [
    "OpenSearch AWS की प्रबंधित सेवा है जो खोज, लॉग विश्लेषण और पूर्ण‑पाठ खोज कार्यभार को संभालती है.\n\n      विचलन उपयोगी सेवाएँ हैं, लेकिन वे इस सूची में विशेष रूप से निर्मित खोज इंजन नहीं हैं:\n      - ElastiCache: मुख्यतः एक इन‑मेमोरी कैश। वर्तमान ElastiCache for Valkey में इंडेक्स्ड इन‑मेमोरी डेटा के लिए खोज कमांड शामिल हैं, इसलिए पूरी सेवा को बिना अंतर्निहित खोज के कहना अब सही नहीं है।\n      - Neptune: ग्राफ डेटाबेस; यह पूर्ण‑पाठ खोज के लिए OpenSearch के साथ एकीकृत हो सकता है।\n      - Redshift: SQL विश्लेषण के लिए डेटा वेयरहाउस।\n      - DocumentDB: दस्तावेज़ डेटाबेस जिसमें समर्थित संस्करणों में MongoDB‑संगत टेक्स्ट खोज होती है."
  ],
